yle=&quot;color:black&quot;&gt;灣上市上櫃公司亞昕集團分工合作，聯&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; &lt;span style=&quot;font-size:11.5pt&quot;&gt;&lt;span style=&quot;font-family:&amp;quot;新細明體&amp;quot;,&amp;quot;serif&amp;quot;&quot;&gt;&lt;span style=&quot;color:black&quot;&gt;手打造寶得利仕女時尚品牌科技商場，&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; &lt;span style=&quot;font-size:11.5pt&quot;&gt;&lt;span style=&quot;font-family:&amp;quot;新細明體&amp;quot;,&amp;quot;serif&amp;quot;&quot;&gt;&lt;span style=&quot;color:black&quot;&gt;該商場的計劃目前已經完成購地，有信&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; &lt;span style=&quot;font-size:11.5pt&quot;&gt;&lt;span style=&quot;font-family:&amp;quot;新細明體&amp;quot;,&amp;quot;serif&amp;quot;&quot;&gt;&lt;span style=&quot;color:black&quot;&gt;心讓大家對寶得利創意商城刮目相看&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br /&gt;
&lt;span style=&quot;font-size:11.5pt&quot;&gt;&lt;span style=&quot;font-family:&amp;quot;Arial&amp;quot;,&amp;quot;sans-serif&amp;quot;&quot;&gt;&lt;span style=&quot;color:black&quot;&gt;(&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span style=&quot;font-size:11.5pt&quot;&gt;&lt;span style=&quot;font-family:&amp;quot;新細明體&amp;quot;,&amp;quot;serif&amp;quot;&quot;&gt;&lt;span style=&quot;color:black&quot;&gt;原文網址&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span style=&quot;font-size:11.5pt&quot;&gt;&lt;span style=&quot;font-family:&amp;quot;Arial&amp;quot;,&amp;quot;sans-serif&amp;quot;&quot;&gt;&lt;span style=&quot;color:black&quot;&gt;http://www.richmarcom.tw/news/detail.aspx?&amp;amp;Subject_id=25186)&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

